var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"가브리엘, 너어어어!!","JPN":"ガブリエル、あなたね！！","ENG":"Gabriel, you!!","TWN":"加布里埃爾，你！！！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"으음? 왜 그러는가, 소녀여?","JPN":"ん？　どうした、少女。","ENG":"Hmm? What is it, girl?","TWN":"嗯？我說少女，是又發生什麼事嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"왜 그러긴! 네가 지금 라면 받침으로 쓰고 있는 그거 때문이지!","JPN":"どうもこうも……あなたが今、鍋敷きにしているそれだよ！","ENG":"What do you think? The thing you’re using as a pot stand!","TWN":"什麼～什麼事！你現在拿來當墊子的那個東西！！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그건 내가 블랙 네트워크를 한참 뒤져서 어렵게 구한 비디오 테이프란 말이야!","JPN":"それは、私がブラックネットワークをあさりまくって、やっと手に入れたビデオテープなの！","ENG":"I got that video tape from the Dark Network! You know how hard it was to find it?","TWN":"那是我找遍黑色網路好不容以才找到的錄影帶欸！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"초고가의 레어 아이템이라 테이프 닳지 않게 재생도 안 했었는데!","JPN":"超高価なレアアイテムだから、テープが傷まないように再生もまだしてなかったんだよ！？","ENG":"That’s a super expensive rare item; I didn’t even play it because I was afraid that I might damage it!","TWN":"這麼珍貴的東西，我多怕弄壞它，所以到現在都還沒播放過！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"초고가의 레어 아이템이라고? 재생하면 닳아 없어질 만큼 유약하면서?","JPN":"超高価なレアアイテムだと？　再生するれば擦り切れるほど脆いのにか？","ENG":"A super expensive rare item? And it might get damaged if you play it?","TWN":"這麼珍貴的東西？然後播放就會弄壞？這麼脆弱？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"혹시 사기라도 당한 것 아닌가?","JPN":"ひょっとして詐欺にでもあったのではないか？","ENG":"Are you sure you weren’t tricked?","TWN":"你是不是被騙啦？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그런 게 아냐! 그 테이프에는 가면 카운터 무인편 환상의 미방영 에피소드가 담겨 있다구!","JPN":"そんなんじゃないって！　そのテープには仮面カウンター無印の幻の未放送エピソードが収録されてるの！","ENG":"No! I’m sure that tape contains the legendary episode of the Masked Counter that never aired.","TWN":"才不是！那個錄影帶裡面的內容，可是蒙面制裁者[無印篇]中，從未放映過的夢幻花絮欸！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그러니까 저리 비켜! 열 때문에 변형되기라도 하면 큰일이라고!","JPN":"だからどけて！　熱で変形でもしたら大変なんだから！","ENG":"Give it back to me! Heat might ruin the tape!","TWN":"走開啦！上面給我墊這麼熱的東西，要是錄影帶變形的話怎麼辦！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"기다려라! 지금 잡아 빼면 라면 냄비의 균형이……!","JPN":"待ちたまえ！　今引っ張ったら、鍋のバランスが……！","ENG":"Wait! The pot will flip over if you just pull it out like that...","TWN":"等一下啦！你現在拿走的話，鍋子會不平衡……！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"내, 내 라면이…! 아직 한 입도 못 먹었건만…!","JPN":"わ、私のラーメンが……！　まだ一口も食べてないのに……！","ENG":"My noodles! I didn’t even get a bite!","TWN":"我…我的泡麵…！我連一口都還沒吃到…！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"흥. 자업자득이다, 이 악당아. 메~롱.","JPN":"ふん。自業自得だね、この悪党め。べ～っだ！","ENG":"You brought it on yourself, you villain.","TWN":"哼！活該！你這個壞蛋，ㄌㄩㄝ～"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……얌전히 돌려달라고 했으면 주었을 것이다. 소녀여.","JPN":"……普通に返せと言えばいいものを。","ENG":"...I would have just returned the tape if you asked nicely, girl.","TWN":"……你好好跟我說的話，我會還你。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"하지만 그대는 내 소중한 요리와 식사 준비에 들어간 노고를 모욕했다.","JPN":"だが、君は大切な私の料理と、その準備のための手間を侮辱した。","ENG":"But you insulted my meal and my effort into making it.","TWN":"但你侮辱了我珍貴的料理和準備過程中付出的心血。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"타인을 개의치 않는 그 사악한 집착! 파사의 심판자로서 용납할 수 없다!","JPN":"他人を顧みないその邪悪な執着！　破邪の審判者として、許すことはできん！","ENG":"Such an evil obsession! I, the Judicator of Evil will not let this go!","TWN":"這種不在乎他人死活的心態！身為破邪審判者的我，絕對無法原諒！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"하, 그렇게 나오신다 이거지?","JPN":"はっ、なるほど！","ENG":"Hah, you dare?","TWN":"哈，竟然還有臉說我？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"남의 소중한 물건을 함부로 다루는 악당! 정의의 이름으로 용서할 수 없다!","JPN":"他人の大切なものを粗末に扱う悪党め！　正義の名のもとに、成敗してやる！","ENG":"You’re the villain who took my precious tape! I’ll punish you in the name of justice!","TWN":"隨便把人家珍貴的東西拿走的壞蛋！我要以正義之名懲罰你！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"오의! 극진 광호장!!","JPN":"奥義！　激震狂虎掌！！","ENG":"Ultimate Raging Tiger Strike!","TWN":"伏虎掌！！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"……경위는 대충 이런데요, 실장님.","JPN":"……ということになったんだけど、室長。","ENG":"So that’s how it happened, Chief.","TWN":"……事情的經過就是這樣，室長。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"하지만 가브리엘 쟤가 먼저 제 테이프를 건드린 게 잘못 아니에요?","JPN":"でも、ガブリエルが先に私のビデオテープに触ったのがいけないでしょ！？","ENG":"But Gabriel used my tape as a pot stand; he started it.","TWN":"可是是加布里埃爾先拿走我的錄影帶的，是他不對吧？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}}]`);export{e as default};